"""
dither.py — ブルーノイズディザリング

SciPy/FFT への依存を排除するため、64x64 のブルーノイズマスクを埋め込みデータとして保持。
"""

import numpy as np
import base64

# 64x64 Blue Noise Mask (Normalized 0-255)
BLUE_NOISE_B64 = ""

def _get_blue_noise_mask():
    """Base64からマスクを復元"""
    data = base64.b64decode(BLUE_NOISE_B64)
    mask = np.frombuffer(data, dtype=np.uint8).reshape((64, 64))
    return mask.astype(np.float32) / 255.0

def apply_blue_noise_dithering(image, bit_depth=8):
    """
    画像にブルーノイズディザリングを適用する
    image: (H, W, 3) float32, range [0, 1]
    bit_depth: 8 or 16
    """
    h, w, c = image.shape
    # ノイズの強さは量子化ステップの 1 LSB 程度
    scale = 1.0 / (2**bit_depth - 1)
    
    # 埋め込みマスクの取得
    mask = _get_blue_noise_mask()
    mask_size = 64
    
    # 画像全体にタイル状に配置
    tile_h = h // mask_size + 1
    tile_w = w // mask_size + 1
    tiled_mask = np.tile(mask, (tile_h, tile_w))[:h, :w]
    tiled_mask = tiled_mask[..., np.newaxis] # (H, W, 1)
    
    # ノイズを加算してクリップ
    # blue_noise (0-1) を中心 0 にシフト (-0.5 to 0.5)
    noise = (tiled_mask - 0.5) * scale
    
    return np.clip(image + noise, 0.0, 1.0).astype(np.float32)
